def greet():
    return "hi"

print(greet())  # 调用后才执行函数体

def square(n):
    return n * n

print(square(3))  # 9

def bad():
    print(10)   # 屏幕有 10，返回 None

def good():
    return 10

x = bad()   # x 是 None
y = good()  # y 是 10

def greeting(name):
    return "hi " + name

print(greeting("Ada"))  # hi Ada
